Here are the public test cases for feature1_asset_url_normalization:
{
  "description": "Asset-backed editor resource paths are rendered as browser URLs, with cache query strings removed only where a directory-style base path is required.",
  "cases": [
    {
      "input": {
        "action": "asset_paths",
        "assets": {
          "bundles/editor/": "/static/editor/?v=2",
          "bundles/editor/editor.js": "/static/editor/editor.js?v=2"
        },
        "base_path": "bundles/editor/",
        "js_path": "bundles/editor/editor.js"
      },
      "expected_output": "base_path=/static/editor/\njs_path=/static/editor/editor.js?v=2\n"
    }
  ]
}

Here are the public test cases for feature2_widget_script_generation:
{
  "description": "Editor startup scripts render the target element id, normalized language data, selected startup mode, and input synchronization code as JavaScript.",
  "cases": [
    {
      "input": {
        "action": "widget_script",
        "element_id": "body",
        "locale_source": "request_stack",
        "locale": "pt_BR",
        "configuration": {},
        "options": {}
      },
      "expected_output": "CKEDITOR.replace(\"body\", {\"language\":\"pt-br\"});\n"
    }
  ]
}

Here are the public test cases for feature3_content_css_and_filebrowser_urls:
{
  "description": "Widget configuration converts stylesheet asset paths and browser route declarations into the final JavaScript configuration URLs.",
  "cases": [
    {
      "input": {
        "action": "widget_script",
        "element_id": "body",
        "assets": {
          "theme.css": "/assets/theme.css?v=9"
        },
        "configuration": {
          "contentsCss": "theme.css"
        },
        "options": {}
      },
      "expected_output": "CKEDITOR.replace(\"body\", {\"contentsCss\":[\"\\/assets\\/theme.css\"]});\n"
    }
  ]
}

Here are the public test cases for feature4_raw_javascript_configuration_values:
{
  "description": "Configuration values that are intended to be JavaScript expressions are emitted without JSON string quoting while ordinary values remain JSON encoded.",
  "cases": [
    {
      "input": {
        "action": "widget_script",
        "element_id": "body",
        "configuration": {
          "protectedSource": [
            "/<\\?[\\s\\S]*?\\?>/g",
            "/<%[\\s\\S]*?%>/g"
          ]
        },
        "options": {}
      },
      "expected_output": "CKEDITOR.replace(\"body\", {\"protectedSource\":[/<\\?[\\s\\S]*?\\?>/g,/<%[\\s\\S]*?%>/g]});\n"
    }
  ]
}

Here are the public test cases for feature5_auxiliary_registration_scripts:
{
  "description": "Auxiliary editor resources are rendered as JavaScript snippets that register plugins, style sets, template sets, and teardown behavior.",
  "cases": [
    {
      "input": {
        "action": "destroy_script",
        "element_id": "body"
      },
      "expected_output": "if (CKEDITOR.instances[\"body\"]) { CKEDITOR.instances[\"body\"].destroy(true); delete CKEDITOR.instances[\"body\"]; }\n"
    },
    {
      "input": {
        "action": "plugin_script",
        "assets": {
          "plugins/wordcount/": "/static/wordcount/?v=2"
        },
        "name": "wordcount",
        "plugin": {
          "path": "plugins/wordcount/",
          "filename": "plugin.js"
        }
      },
      "expected_output": "CKEDITOR.plugins.addExternal(\"wordcount\", \"/static/wordcount/\", \"plugin.js\");\n"
    }
  ]
}

Here are the public test cases for feature6_named_resource_collections:
{
  "description": "Named collections preserve supplied entries, replace entries with the same name, merge selected editor configuration data, and expose neutral missing-entry errors.",
  "cases": [
    {
      "input": {
        "action": "named_configs",
        "initial": {},
        "operations": []
      },
      "expected_output": "has_entries=no\ndefault=null\nentries=[]\n"
    },
    {
      "input": {
        "action": "named_configs",
        "initial": {
          "default": {
            "toolbar": "basic",
            "uiColor": "#ffffff"
          }
        },
        "default": "default",
        "operations": [
          {
            "type": "merge",
            "name": "default",
            "value": {
              "uiColor": "#000000"
            }
          }
        ]
      },
      "expected_output": "has_entries=yes\ndefault=default\nentries={\"default\":{\"toolbar\":\"basic\",\"uiColor\":\"#000000\"}}\n"
    },
    {
      "input": {
        "action": "read_config",
        "initial": {},
        "name": "missing"
      },
      "expected_output": "error=missing_config\nname=missing\n"
    }
  ]
}

Here are the public test cases for feature7_form_view_defaults_and_overrides:
{
  "description": "Creating an editor form view exposes default view variables, applies configured defaults, accepts per-form overrides, and omits editor-only variables when disabled.",
  "cases": [
    {
      "input": {
        "action": "form_view",
        "form_options": {}
      },
      "expected_output": "view={\"enable\":true,\"async\":false,\"autoload\":true,\"auto_inline\":true,\"inline\":false,\"jquery\":false,\"require_js\":false,\"input_sync\":false,\"filebrowsers\":[],\"base_path\":\"bundles/ivoryckeditor/\",\"js_path\":\"bundles/ivoryckeditor/ckeditor.js\",\"jquery_path\":\"bundles/ivoryckeditor/adapters/jquery.js\",\"config\":[],\"plugins\":[],\"styles\":[],\"templates\":[]}\n"
    },
    {
      "input": {
        "action": "form_view",
        "defaults": {
          "enable": false
        },
        "form_options": {
          "config": {
            "toolbar": {
              "foo": "bar"
            }
          },
          "plugins": {
            "wordcount": {
              "path": "/my/path",
              "filename": "plugin.js"
            }
          }
        }
      },
      "expected_output": "view={\"enable\":false}\n"
    }
  ]
}
